<body>

<div id="sheet">
    <table id="grid" style="width:600px; height:400px;">
        <!-- Column headers -->
        <tr>
            <th>A</th><th>B</th><th>C</th><th>D</th><th>E</th><th>F</th><th>G</th><th>H</th><th>I</th><th>J</th>
        </tr>

        <!-- Cell data -->
        <tr>
            <td class="cell" onclick="updateCell('A1')">0</td>
            <td class="cell" onclick="updateCell('B1')">0</td>
            <td class="cell" onclick="updateCell('C1')">0</td>
