            <td class="cell" onclick="updateCell('I1')">0</td>
            <td class="cell" onclick="updateCell('J1')">0</td>
        </tr>

        <!-- Row data -->
        <tr>
            <td class="cell" onclick="updateCell('A2')">10</td>
            <td class="cell" onclick="updateCell('B2')">20</td>
            <td class="cell" onclick="updateCell('C2')">30</td>
            <td class="cell" onclick="updateCell('D2')">40</td>
            <td class="cell" onclick="updateCell('E2')">50</td>
            <td class="cell" onclick="updateCell('F2')">60</td>
            <td class="cell" onclick="updateCell('G2')">70</td>
            <td class="cell" onclick="updateCell('H2')">80</td>
            <td class="cell" onclick="updateCell('I2')">90</td>
            <td class="cell" onclick="updateCell('J2')">100</td>
        </tr>

        <!-- Continue with 9 more rows -->
    </table>

    <!-- Export button -->
    <button id="export" onclick="exportCSV()">Export CSV</button>

    <!-- Computed values display area -->
    <div id="computedOutput"></div>

<script>
    // Cell data structure
    const cells = [
        { rawValue: 0, displayedValue: 0, formula: "" },
        { rawValue: 0, displayedValue: 0, formula: "" },
        { rawValue: 0, displayedValue: 0, formula: "" },
        { rawValue: 0, displayedValue: 0, formula: "" },
        { rawValue: 0, displayedValue: 0, formula: "" },
        { rawValue: 0, displayedValue: 0, formula: "" },
        { rawValue: 0, displayedValue: 0, formula: "" },
        { rawValue: 0, displayedValue: 0, formula: "" },
        { rawValue: 0, displayedValue: 0, formula: "" },
        { rawValue: 0, displayedValue: 0, formula: "" },
        { rawValue: 0, displayedValue: 0, formula: "" }
    ];

    // Circular reference detection
    const circularRefs = new Set();

    function detectCircularReferences() {
        cells.forEach(cell => {
            cell.formula = cell.formula.replace(/([A-Z])/g, '\\1$');
            if (cell.formula.includes('=') && cell.formula.startsWith('=')) {
                const regex = new RegExp(`(${cell.row}-${cell.col})`, 'g');
                circularRefs.add(cell.row * 10 + cell.col);
            }
        });
    }

    function updateCell(id) {
        const cellData = cells.find(c => c.rawValue === id);

        // If cell is not being edited (formula exists), show raw text
        if (!cellData.formula && cellData.rawValue !== 0) {
            cellData.displayedValue = cellData.rawValue;
            cellData.originalValue = cellData.rawValue;

            // Check for circular references
            detectCircularReferences();
        }

        // If cell is being edited, show computed value (if formula exists)
        if (cellData.formula) {
            const computedValue = computeFormula(cellData.formula);
            cellData.displayedValue = computedValue;

            // Update all cells in the formula chain
            updateAllCellsInChain(cellData.row * 10 + cell.col, computedValue);
        }
    }

    function computeFormula(formula) {
        if (!formula.startsWith('=')) return "#ERR";

        // Remove leading/trailing spaces and trim
        const cleanFormula = formula.trim();

        // Check for empty cells (count as 0)
        if (cleanFormula === "") return 0;

        // Evaluate the formula
        try {
            // Use a simple evaluator that handles basic arithmetic
            let result = 0;
            let sign = 1;

            // Parse numbers and operators
            for (let i = 0; i < cleanFormula.length; i++) {
                const char = cleanFormula[i];

                if (char === '+' || char === '-') {
                    sign *= char;
                } else if (char === '*' || char === '/') {
                    result *= parseFloat(char);
                }
            }

            // Handle parentheses
            let stack = [];
            for (let i = 0; i < cleanFormula.length; i++) {
                const char = cleanFormula[i];

                if (char === '(') {
                    stack.push(result);
                    result = 0;
                } else if (char === ')') {
                    stack.pop();
                    result += parseFloat(stack.pop());
                }
            }

            return sign * result;
        } catch (error) {
            return "#ERR";
        }
    }

    function updateAllCellsInChain(row, value) {
        const rowId = row + 1; // Convert to 1-based for cell reference

        cells.forEach(cell => {
            if (cell.row === row && cell.col === 0) { // Current cell being updated
                cell.formula = computeFormula(value);
                cell.originalValue = value;

                // Propagate changes through formula chain
                const currentRow = row + 1;
                for (let col = 1; col < 10; col++) {
                    if (cell.row === currentRow && cell.col === col) {
                        updateCell(`${row}Col${col}`);
                    }
                }
            }
        });
    }

    function exportCSV() {
        const csvData = [];

        cells.forEach(cell => {
            // Convert computed value to string
            let computedValue;
            if (cell.displayedValue === "") {
                computedValue = 0;
            } else {
                computedValue = parseInt(cell.displayedValue, 10);
            }

            csvData.push(`${computedValue}`);
        });

        const csvText = csvData.join(",");

        // Create textarea for CSV
        const csvArea = document.getElementById("csv");
        csvArea.value = csvText;
    }

    // Initialize circular references detection
    detectCircularReferences();
</script>
</body>
</html>
